// ── Parse CellarTracker CSV ──────────────────────────────────────────────────
// CT exports genuine comma-separated CSV with a header row.
// Returns one item per wine row, merged with any tasting notes.

function parseCSV(raw) {
  const lines = raw.trim().split('\n');
  if (lines.length < 2) return [];

  // CT sometimes uses Windows line endings
  const clean = lines.map(l => l.replace(/\r$/, ''));

  // Header row — detect delimiter (CT is comma for Format=csv)
  const header = clean[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());

  const rows = [];
  for (let i = 1; i < clean.length; i++) {
    if (!clean[i].trim()) continue;
    // Simple CSV split (handles quoted fields with commas)
    const values = [];
    let cur = '', inQ = false;
    for (const ch of clean[i] + ',') {
      if (ch === '"') { inQ = !inQ; }
      else if (ch === ',' && !inQ) { values.push(cur.trim()); cur = ''; }
      else cur += ch;
    }
    const obj = {};
    header.forEach((h, idx) => { obj[h] = values[idx] ?? ''; });
    rows.push(obj);
  }
  return rows;
}

const inventoryRaw = $input.all()[0].json.data;  // from Fetch CT Inventory node
const notesRaw     = $input.all()[1].json.data;  // from Fetch CT Tasting Notes node

const inventoryRows = parseCSV(inventoryRaw);
const notesRows     = parseCSV(notesRaw);

// ── Index notes by iWine → concatenate all notes for that wine ────────────────
const notesByWine = {};
for (const n of notesRows) {
  const id = n.iWine;
  if (!id) continue;
  if (!notesByWine[id]) notesByWine[id] = { texts: [], latestDate: null };
  if (n.Note) notesByWine[id].texts.push(n.Note.trim());
  if (n.Date) {
    const d = new Date(n.Date);
    if (!notesByWine[id].latestDate || d > new Date(notesByWine[id].latestDate)) {
      notesByWine[id].latestDate = n.Date;
    }
  }
}

// ── Helper: coerce values ─────────────────────────────────────────────────────
const toInt   = v => v && v !== '' ? parseInt(v, 10)   : null;
const toFloat = v => v && v !== '' ? parseFloat(v)     : null;
const toStr   = v => v && v !== '' ? v.trim()          : null;

// ── Build output items ────────────────────────────────────────────────────────
const output = [];
for (const row of inventoryRows) {
  const iwine = row.iWine || row.iwine;
  if (!iwine) continue;

  const noteData    = notesByWine[iwine] || { texts: [], latestDate: null };
  const my_notes    = noteData.texts.length > 0 ? noteData.texts.join(' | ') : null;
  const note_date   = noteData.latestDate || null;

  // Build the text blob that will be embedded.
  // Richer = better recall. Include everything meaningful.
  const embedParts = [
    row.Wine,
    row.Vintage && row.Vintage !== '0' ? `Vintage ${row.Vintage}` : null,
    row.Producer,
    row.Type,
    row.Color,
    row.Category,   // varietal
    row.Locale,
    row.Appellation,
    row.Region,
    row.Country,
    toInt(row.Qty)  ? `${row.Qty} bottles in cellar` : null,
    toStr(row.Location) ? `Location: ${row.Location}` : null,
    toStr(row.Bin)      ? `Bin: ${row.Bin}` : null,
    toInt(row.BeginConsume) && toInt(row.EndConsume)
      ? `Drink ${row.BeginConsume}–${row.EndConsume}` : null,
    toFloat(row.CT)      ? `CellarTracker community score ${row.CT}` : null,
    toFloat(row.MyScore) ? `My score ${row.MyScore}` : null,
    my_notes ? `Tasting notes: ${my_notes}` : null
  ].filter(Boolean);

  output.push({
    json: {
      // Structured fields
      ct_iwine:       toInt(iwine),
      wine:           toStr(row.Wine),
      vintage:        toInt(row.Vintage) || null,
      producer:       toStr(row.Producer),
      wine_type:      toStr(row.Type),
      color:          toStr(row.Color),
      varietal:       toStr(row.Category),
      appellation:    toStr(row.Appellation),
      region:         toStr(row.Region),
      country:        toStr(row.Country),
      locale:         toStr(row.Locale),
      qty:            toInt(row.Qty)      ?? 0,
      location:       toStr(row.Location),
      bin:            toStr(row.Bin),
      price:          toFloat(row.Price),
      valuation:      toFloat(row.Valuation),
      drink_from:     toInt(row.BeginConsume),
      drink_to:       toInt(row.EndConsume),
      ct_score:       toFloat(row.CT),
      my_score:       toFloat(row.MyScore),
      my_notes,
      note_date,
      last_synced_at: new Date().toISOString(),
      removed_at:     null,   // active — nulled on upsert
      raw_ct_row:     JSON.stringify(row),
      // Embedding input
      embedding_text: embedParts.join('. ')
    }
  });
}

return output;

// Merge the embedding vector back into the wine record.
// The HTTP node replaces $json with the OAI response,
// so we carry the original wine fields via a workaround:
// we stored them in the previous node's output which is
// available via $('Parse CSV + Merge Notes').item

const oaiResponse  = $json;                                   // OpenAI response
const wineRecord   = $('Parse CSV + Merge Notes').item.json;  // original wine fields

const embedding = oaiResponse?.data?.[0]?.embedding;
if (!embedding) throw new Error(`No embedding returned for wine: ${wineRecord.wine}`);

// Return merged record ready for Supabase upsert
return {
  json: {
    ...wineRecord,
    embedding: `[${embedding.join(',')}]`,  // Supabase expects stringified array for vector type
    embedding_text: undefined               // don't store the raw text blob
  }
};

// Collect all ct_iwine values that were present in today's export.
// Any row in Supabase NOT in this set and not already soft-deleted → set removed_at.

const allItems = $input.all();
const activeIwines = allItems.map(i => i.json.ct_iwine).filter(Boolean);

// Pass as a single item so the next HTTP node can use it
return [{ json: { active_iwines: activeIwines } }];

// Build a summary thought to capture in dave-brain
const upserted     = $('Parse CSV + Merge Notes').all().length;
const softDeleted  = $input.all().length;  // rows returned from PATCH
const now          = new Date().toISOString().slice(0,10);

return [{
  json: {
    summary: `Wine inventory sync ${now}: ${upserted} wines upserted, ${softDeleted} soft-deleted. Source: CellarTracker.`
  }
}];
